:root {
  --bg: #050505;
  --panel: #111214;
  --line: rgba(255, 255, 255, 0.08);
  --text: #f4f4f4;
  --muted: #b8bcc3;
  --red: #d91f26;
  --red-dark: #bc181f;
  --gold: #d8a84f;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: smooth;
}

body {
  margin: 0;
  background: var(--bg);
  color: var(--text);
  font-family: Arial, Helvetica, sans-serif;
}

a {
  text-decoration: none;
  color: inherit;
}

img {
  display: block;
  max-width: 100%;
}

button,
input,
textarea {
  font: inherit;
}

.container {
  width: min(1320px, 92vw);
  margin: 0 auto;
}

/* =========================
   HEADER
========================= */

.siteHeader {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 500;
}

/* TOP BAR */
.topBar {
  background: #d91512;
  overflow: hidden;
  height: 42px;
  transition: height 0.3s ease, opacity 0.3s ease;
}

.isScrolled .topBar {
  height: 0;
  opacity: 0;
  pointer-events: none;
}

.topBarInner {
  display: grid;
  grid-template-columns: 1fr 1.5fr 1fr;
  align-items: center;
  height: 42px;
}

.topItem {
  height: 42px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
  padding: 0 16px;
  border-right: 1px solid rgba(255, 255, 255, 0.22);
  color: #ffffff;
  font-size: 0.88rem;
  font-weight: 500;
  letter-spacing: 0.01em;
}

.topItem.noBorder {
  border-right: none;
}

.topItemLink {
  text-decoration: none;
  transition: background .15s, opacity .15s;
}
.topItemLink:hover {
  background: rgba(255,255,255,.1);
  opacity: 1;
}
.topItemLink:hover span { color: #ffffff; }

.topItemRight {
  justify-content: flex-end;
  gap: 10px;
}

.topIcon {
  flex-shrink: 0;
  width: 14px;
  height: 14px;
  color: rgba(255, 255, 255, 0.75);
}

/* EN/ES en la topbar */
.topLang {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  justify-content: flex-end;
  margin-left: 14px;
  padding-left: 14px;
  border-left: 1px solid rgba(255, 255, 255, 0.22);
}

.topLangOption {
  border: none;
  background: transparent;
  color: rgba(255, 255, 255, 0.65);
  font-size: 0.78rem;
  font-weight: 800;
  cursor: pointer;
  padding: 0;
  letter-spacing: 0.06em;
  transition: color 0.2s ease;
}

.topLangOption.active {
  color: #ffffff;
}

.topLangOption:hover {
  color: rgba(255, 255, 255, 0.9);
}

.topLangDivider {
  color: rgba(255, 255, 255, 0.35);
  font-size: 0.74rem;
}

/* NAVBAR */
.navBar {
  background: transparent;
  overflow: visible;
  transition: background 0.3s ease, box-shadow 0.3s ease;
  position: relative;
}

.navScrolled {
  background: rgba(5,5,5,0.97) !important;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  box-shadow: 0 2px 24px rgba(0,0,0,0.5);
}

.navInner {
  display: grid;
  grid-template-columns: 1fr 1.5fr 1fr;
  align-items: center;
  height: 76px;
  overflow: visible;
  transition: height 0.3s ease;
}

.navScrolled .navInner {
  height: 120px;
}

/* Hamburger — hidden desktop */
.navHamburger { display: none; }

/* Mobile menu + overlay — hidden on desktop */
.mobileMenu    { display: none; }
.mobileOverlay { display: none; }

/* BRAND */
.brand {
  display: flex;
  align-items: center;
}

.brandLogo {
  width: 240px;
  height: auto;
  display: block;
  margin-top: -18px;
  transition: width 0.3s ease, margin-top 0.3s ease;
}

.brandScrolled {
  width: 200px;
  margin-top: 0;
}

/* MENU */
.navMenu {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 34px;
}

.navLink {
  color: #ffffff;
  font-size: 0.96rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  line-height: 1;
  transition: color 0.2s ease;
}

.navLink:hover {
  color: #d91f26;
}

/* ACTIONS */
.navActions {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  gap: 14px;
}

/* BOOK SERVICE */
.navBookBtn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  white-space: nowrap;
  height: 44px;
  padding: 0 24px;
  background: var(--red);
  color: #ffffff;
  border-radius: 20px 0 20px 0;
  font-size: 0.84rem;
  font-weight: 800;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  line-height: 1;
  box-shadow: 0 4px 16px rgba(217, 31, 38, 0.35);
  transition: background 0.2s ease, transform 0.2s ease;
}

.navBookBtn:hover {
  background: var(--red-dark);
  transform: translateY(-1px);
  color: #ffffff;
}

/* LANGUAGE */
.langSwitch {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  height: 36px;
  padding: 0 10px;
  border: 1px solid rgba(255, 255, 255, 0.15);
  border-radius: 999px;
  background: rgba(255, 255, 255, 0.04);
}

.langIcon {
  display: flex;
  align-items: center;
  color: #ffffff;
  opacity: 0.65;
}

.langDivider {
  color: rgba(255, 255, 255, 0.28);
  font-size: 0.74rem;
}

.langOption {
  border: none;
  background: transparent;
  color: rgba(255, 255, 255, 0.5);
  font-size: 0.76rem;
  font-weight: 800;
  cursor: pointer;
  padding: 0;
  letter-spacing: 0.06em;
  transition: color 0.2s ease;
}

.langOption.active {
  color: #ffffff;
}

.langOption:hover {
  color: #d91f26;
}

/* DROPDOWN */
.navDropWrap {
  position: relative;
}

.navDropTrigger {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  background: none;
  border: none;
  padding: 0;
  cursor: pointer;
  color: #ffffff;
  font-size: 0.96rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  line-height: 1;
  transition: color 0.2s ease;
}

.navDropTrigger:hover,
.navDropTrigger.open {
  color: #d91f26;
}

.dropChevron {
  transition: transform 0.2s ease;
}

.navDropTrigger.open .dropChevron {
  transform: rotate(180deg);
}

.navDropMenu {
  position: absolute;
  top: calc(100% + 14px);
  left: 50%;
  transform: translateX(-50%);
  min-width: 190px;
  background: rgba(10, 10, 12, 0.97);
  border: 1px solid rgba(255, 255, 255, 0.10);
  border-radius: 14px;
  padding: 6px;
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  z-index: 100;
  box-shadow: 0 16px 40px rgba(0, 0, 0, 0.45);
  animation: dropIn 0.15s ease;
}

@keyframes dropIn {
  from { opacity: 0; transform: translateX(-50%) translateY(-6px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}

.navDropItem {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 11px 14px;
  color: rgba(255, 255, 255, 0.82);
  font-size: 0.92rem;
  font-weight: 500;
  border-radius: 10px;
  transition: background 0.15s ease, color 0.15s ease;
}

.navDropItem svg {
  opacity: 0.55;
  flex-shrink: 0;
  transition: opacity 0.15s ease;
}

.navDropItem:hover {
  background: rgba(217, 31, 38, 0.14);
  color: #ffffff;
}

.navDropItem:hover svg {
  opacity: 1;
}

/* =========================
   HERO
========================= */

.hero {
  position: relative;
  min-height: 100vh;  /* full viewport — el header flota encima */
  overflow: hidden;
}

.heroImage {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  object-position: center right;
  transform: scale(1.02);
}

/*
  Overlay: muy oscuro a la izquierda (0.92) donde está el texto,
  se aclara hacia la derecha con tinte rojizo.
  El texto NUNCA compite con la foto.
*/
.heroOverlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    100deg,
    rgba(0, 0, 0, 0.92) 0%,
    rgba(0, 0, 0, 0.82) 30%,
    rgba(0, 0, 0, 0.52) 58%,
    rgba(100, 5, 10, 0.28) 100%
  );
}

.heroContent {
  position: relative;
  z-index: 2;
  display: flex;
  align-items: center;
  min-height: 100vh;
  padding: 120px 0 80px;
}

.heroCopy {
  max-width: 680px;
}

/* EYEBROW */
.eyebrow {
  color: var(--gold);
  font-size: 0.82rem;
  letter-spacing: 0.22em;
  font-weight: 600;
  text-transform: uppercase;
  margin: 0 0 18px;
}

/* H1 */
.hero h1 {
  margin: 0 0 16px;
  font-size: clamp(3rem, 7vw, 6rem);
  line-height: 0.96;
  letter-spacing: -0.05em;
  font-weight: 700;
  color: #ffffff;
}

/* Palabra clave destacada en rojo */
.heroAccent {
  color: var(--red);
}

/* Subtítulo — corto y directo */
.heroSub {
  color: #d8dade;
  font-size: 1.08rem;
  line-height: 1.7;
  max-width: 540px;
  margin: 0 0 18px;
}

/* SOCIAL PROOF */
.heroRating {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 32px;
  font-size: 0.9rem;
  color: #c8cad0;
}

.heroStars {
  color: #f5c842;
  font-size: 0.88rem;
  letter-spacing: 0.04em;
}

/* HERO ACTIONS */
.heroActions {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  align-items: center;
}

/* PRIMARY CTA */
.heroPrimary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 220px;
  height: 56px;
  padding: 0 32px;
  background: var(--red);
  color: #ffffff;
  border: none;
  border-radius: 20px 0 20px 0;
  font-size: 0.92rem;
  font-weight: 800;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  box-shadow: 0 8px 28px rgba(217, 31, 38, 0.35);
  transition: background 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease;
}

.heroPrimary:hover {
  background: var(--red-dark);
  transform: translateY(-2px);
  box-shadow: 0 12px 36px rgba(217, 31, 38, 0.45);
}

/* SECONDARY CTAs — ghost, menor peso visual */
.heroSecondary {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  justify-content: center;
  min-width: 140px;
  height: 48px;
  padding: 0 20px;
  border-radius: 14px;
  border: 1px solid rgba(255, 255, 255, 0.20);
  color: rgba(255, 255, 255, 0.82);
  background: rgba(255, 255, 255, 0.04);
  font-size: 0.88rem;
  font-weight: 500;
  letter-spacing: 0.02em;
  transition: all 0.2s ease;
}

.heroSecondary:hover {
  background: rgba(255, 255, 255, 0.10);
  border-color: rgba(255, 255, 255, 0.36);
  color: #ffffff;
}

.heroSecIcon {
  flex-shrink: 0;
  opacity: 0.75;
}

/* =========================
   TRUST BAR — hero bottom
========================= */

.trustBar {
  background: rgba(0,0,0,0.55);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  border-top: 1px solid rgba(255,255,255,0.07);
}

.trustGrid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 0;
  padding: 0;
}

.trustItem {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 20px 24px;
  border-right: 1px solid rgba(255,255,255,0.07);
}

.trustItem:last-child {
  border-right: none;
}

.trustDot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--red);
  flex-shrink: 0;
  margin-top: 5px;
}

.trustItem strong {
  display: block;
  font-size: 0.88rem;
  font-weight: 600;
  color: #ffffff;
  margin-bottom: 3px;
}

.trustItem span {
  display: block;
  color: rgba(255,255,255,0.45);
  font-size: 0.8rem;
  line-height: 1.5;
}

/* =========================
   SECTIONS
========================= */

.section {
  padding: 88px 0;
}

.sectionDark {
  background: #090a0d;
}

.sectionHead {
  max-width: 780px;
  margin: 0 auto 36px;
  text-align: center;
}

.leftAlign {
  text-align: left;
  margin-left: 0;
}

.sectionHead h2,
.splitCopy h2,
.trainingGrid h2,
.contactGrid h2,
.innerPageBox h1 {
  margin: 0 0 18px;
  font-size: clamp(3rem, 7vw, 6rem);
  line-height: 0.96;
  letter-spacing: -0.05em;
  font-weight: 700;
}

.sectionHead p,
.splitCopy p,
.splitCopy li,
.trainingGrid p,
.contactGrid p,
.innerPageBox p {
  color: #e0e2e5;
  font-size: 1.12rem;
  line-height: 1.75;
  max-width: 720px;
}

.servicesGrid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 22px;
}

/* =========================
   SERVICES — 3D hologram
========================= */

.svcSection {
  background: #07080b;
  padding: 96px 0;
  position: relative;
  overflow: hidden;
}

.svcSection::before {
  content: "";
  position: absolute;
  top: 40%;
  left: 50%;
  transform: translate(-50%,-50%);
  width: 900px;
  height: 500px;
  background: radial-gradient(ellipse, rgba(217,31,38,.05) 0%, transparent 70%);
  pointer-events: none;
}

.svcHeader {
  text-align: center;
  margin-bottom: 64px;
  position: relative;
  z-index: 1;
}

.svcMainTitle {
  font-size: clamp(2.8rem, 5vw, 5rem);
  font-weight: 700;
  letter-spacing: -0.04em;
  line-height: 0.95;
  color: #ffffff;
  margin: 12px 0 18px;
}

.svcMainSub {
  color: var(--muted);
  font-size: 1.08rem;
  line-height: 1.7;
  max-width: 500px;
  margin: 0 auto;
}

.svcGrid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
  position: relative;
  z-index: 1;
}

/* 3D CARD */
.svcCard {
  /* reveal start */
  opacity: 0;
  transform: perspective(700px) translateY(32px);
  transition:
    opacity 0.6s cubic-bezier(.22,1,.36,1),
    transform 0.6s cubic-bezier(.22,1,.36,1);
}

.svcCardVisible {
  opacity: 1;
  transform: perspective(700px) translateY(0) rotateX(0deg) rotateY(0deg);
}

.svcCard {
  position: relative;
  background: rgba(255,255,255,.04);
  border: 1px solid rgba(255,255,255,.08);
  border-radius: 24px;
  padding: 32px 28px 28px;
  overflow: hidden;
  cursor: default;
  /* smooth return */
  transition: transform 0.4s cubic-bezier(0.23,1,0.32,1), border-color 0.3s ease;
  transform-style: preserve-3d;
  will-change: transform;
  --mx: 50%;
  --my: 50%;
}

.svcCard:hover {
  border-color: rgba(217,31,38,.25);
}

/* Hologram shine — moves with mouse via --mx/--my */
.svcShine {
  position: absolute;
  inset: 0;
  border-radius: 24px;
  pointer-events: none;
  background: radial-gradient(
    circle at var(--mx) var(--my),
    rgba(255,255,255,.10) 0%,
    rgba(255,255,255,.04) 30%,
    transparent 65%
  );
  opacity: 0;
  transition: opacity 0.2s ease;
  z-index: 1;
}

.svcCard:hover .svcShine {
  opacity: 1;
}

/* Red glow bottom */
.svcHalo {
  position: absolute;
  bottom: -50px;
  left: 50%;
  transform: translateX(-50%);
  width: 180px;
  height: 120px;
  background: radial-gradient(ellipse, rgba(217,31,38,.2) 0%, transparent 70%);
  pointer-events: none;
  opacity: 0;
  transition: opacity 0.3s ease;
  z-index: 0;
}

.svcCard:hover .svcHalo {
  opacity: 1;
}

/* ICON — floats up in 3D on hover */
.svcIconWrap {
  width: 72px;
  height: 72px;
  margin-bottom: 22px;
  position: relative;
  z-index: 2;
  transition: transform 0.4s cubic-bezier(0.23,1,0.32,1);
  transform: translateZ(0px);
}

.svcCard:hover .svcIconWrap {
  transform: translateZ(40px) scale(1.1);
}

.svcSvg {
  width: 100%;
  height: 100%;
}

.svcCardTitle {
  font-size: 1.1rem;
  font-weight: 700;
  color: rgba(255,255,255,.85);
  margin: 0 0 10px;
  letter-spacing: -0.01em;
  position: relative;
  z-index: 2;
  transition: color 0.2s ease, transform 0.4s cubic-bezier(0.23,1,0.32,1);
  transform: translateZ(0px);
}

.svcCard:hover .svcCardTitle {
  color: #ffffff;
  transform: translateZ(20px);
}

.svcCardDesc {
  color: rgba(255,255,255,.4);
  font-size: 0.92rem;
  line-height: 1.7;
  margin: 0;
  position: relative;
  z-index: 2;
  transition: color 0.2s ease;
}

.svcCard:hover .svcCardDesc {
  color: rgba(255,255,255,.6);
}

@media (max-width: 900px) {
  .svcGrid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 580px) {
  .svcGrid { grid-template-columns: 1fr; }
}

