/* =========================
   GALLERY — scan / HUD effect
========================= */

.glrySection {
  background: #08090c;
  padding: 96px 0 112px;
  overflow: hidden;
}

.glryHeader { margin-bottom: 52px; }

.glryTitle {
  font-size: clamp(2.4rem, 4.5vw, 4.2rem);
  font-weight: 700;
  letter-spacing: -0.04em;
  line-height: 0.95;
  color: #ffffff;
  margin: 12px 0 14px;
}

.glrySub {
  color: var(--muted);
  font-size: 1.05rem;
  margin: 0;
}

/* Masonry grid */
.glryMasonry {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  grid-template-rows: 220px 220px 180px 260px;
  gap: 10px;
}

.glryCell {
  overflow: hidden;
  border-radius: 12px;
  min-height: 0;
}

/* TILE */
.glryTile {
  width: 100%;
  height: 100%;
  position: relative;
  cursor: zoom-in;
  overflow: hidden;
  background: #111;
  /* start invisible */
  opacity: 0;
  filter: grayscale(1) brightness(0.3);
  transition:
    opacity 0.8s ease,
    filter 1.2s ease;
}

/* After scan — full color */
.glryTile.glryScanned {
  opacity: 1;
  filter: grayscale(0) brightness(1);
}

/* Scan line — sweeps top to bottom on reveal */
.glryScanLine {
  position: absolute;
  left: 0; right: 0;
  height: 2px;
  background: linear-gradient(90deg, transparent, #d91f26, transparent);
  top: -2px;
  z-index: 3;
  opacity: 0;
  pointer-events: none;
}

.glryTile.glryScanned .glryScanLine {
  animation: scanDown 0.9s ease forwards;
}

@keyframes scanDown {
  0%   { top: 0%;   opacity: 1; }
  90%  { top: 100%; opacity: 1; }
  100% { top: 100%; opacity: 0; }
}

/* HUD corner brackets */
.glryBracketTL, .glryBracketTR,
.glryBracketBL, .glryBracketBR {
  position: absolute;
  width: 16px; height: 16px;
  z-index: 4;
  opacity: 0;
  transition: opacity 0.3s ease 0.9s;
  pointer-events: none;
}

.glryTile.glryScanned .glryBracketTL,
.glryTile.glryScanned .glryBracketTR,
.glryTile.glryScanned .glryBracketBL,
.glryTile.glryScanned .glryBracketBR {
  opacity: 1;
}

.glryBracketTL {
  top: 8px; left: 8px;
  border-top: 2px solid #d91f26;
  border-left: 2px solid #d91f26;
  border-radius: 2px 0 0 0;
}
.glryBracketTR {
  top: 8px; right: 8px;
  border-top: 2px solid #d91f26;
  border-right: 2px solid #d91f26;
  border-radius: 0 2px 0 0;
}
.glryBracketBL {
  bottom: 8px; left: 8px;
  border-bottom: 2px solid #d91f26;
  border-left: 2px solid #d91f26;
  border-radius: 0 0 0 2px;
}
.glryBracketBR {
  bottom: 8px; right: 8px;
  border-bottom: 2px solid #d91f26;
  border-right: 2px solid #d91f26;
  border-radius: 0 0 2px 0;
}

/* Index counter */
.glryIndex {
  position: absolute;
  bottom: 10px; left: 12px;
  font-size: 0.62rem;
  font-weight: 700;
  letter-spacing: 0.12em;
  color: rgba(217,31,38,.7);
  z-index: 4;
  opacity: 0;
  transition: opacity 0.3s ease 1s;
  pointer-events: none;
  font-family: monospace;
}

.glryTile.glryScanned .glryIndex { opacity: 1; }

/* Image */
.glryTileImg {
  width: 100%;
  height: 115%;
  object-fit: cover;
  object-position: center;
  display: block;
  will-change: transform;
  transform: scale(1.14) translateY(0);
  transition: transform 0.05s linear;
}

/* Hover overlay */
.glryHover {
  position: absolute;
  inset: 0;
  background: rgba(0,0,0,0);
  display: flex; align-items: center; justify-content: center;
  transition: background 0.2s;
  z-index: 2;
}
.glryHover svg { opacity: 0; transform: scale(0.6); transition: opacity .2s, transform .2s; }
.glryTile:hover .glryHover { background: rgba(0,0,0,0.4); }
.glryTile:hover .glryHover svg { opacity: 1; transform: scale(1); }

/* LIGHTBOX */
.glryLb {
  position: fixed; inset: 0; z-index: 9999;
  background: rgba(0,0,0,0.95);
  display: flex; align-items: center; justify-content: center;
  backdrop-filter: blur(10px);
  animation: lbIn 0.2s ease;
}
@keyframes lbIn { from { opacity:0 } to { opacity:1 } }

.glryLbFrame {
  position: relative;
  max-width: 88vw;
  max-height: 84vh;
}

/* HUD brackets on lightbox */
.glryLbBracketTL, .glryLbBracketTR,
.glryLbBracketBL, .glryLbBracketBR {
  position: absolute;
  width: 24px; height: 24px;
  z-index: 2; pointer-events: none;
}
.glryLbBracketTL { top:-4px; left:-4px; border-top:2px solid #d91f26; border-left:2px solid #d91f26; }
.glryLbBracketTR { top:-4px; right:-4px; border-top:2px solid #d91f26; border-right:2px solid #d91f26; }
.glryLbBracketBL { bottom:-4px; left:-4px; border-bottom:2px solid #d91f26; border-left:2px solid #d91f26; }
.glryLbBracketBR { bottom:-4px; right:-4px; border-bottom:2px solid #d91f26; border-right:2px solid #d91f26; }

.glryLbImg {
  max-width: 88vw; max-height: 84vh;
  object-fit: contain; border-radius: 8px; display: block;
  animation: lbImgIn 0.25s cubic-bezier(.22,1,.36,1);
}
@keyframes lbImgIn { from { opacity:0; transform:scale(.94) } to { opacity:1; transform:scale(1) } }

.glryLbClose {
  position: absolute; top:16px; right:16px;
  width:40px; height:40px; border-radius:50%;
  background:rgba(255,255,255,.1); border:1px solid rgba(255,255,255,.15);
  display:flex; align-items:center; justify-content:center; cursor:pointer;
  transition: background .2s;
}
.glryLbClose:hover { background:rgba(255,255,255,.2); }

.glryLbNav {
  position: absolute; top:50%; transform:translateY(-50%);
  width:46px; height:46px; border-radius:50%;
  background:rgba(255,255,255,.08); border:1px solid rgba(255,255,255,.12);
  display:flex; align-items:center; justify-content:center; cursor:pointer;
  transition: background .2s;
}
.glryLbNav:hover { background:rgba(217,31,38,.2); border-color:rgba(217,31,38,.4); }
.glryLbPrev { left:16px; }
.glryLbNext { right:16px; }

.glryLbCount {
  position:absolute; bottom:16px; left:50%; transform:translateX(-50%);
  color:rgba(255,255,255,.4); font-size:.78rem; letter-spacing:.14em;
  font-family:monospace; margin:0;
}

/* Responsive */
@media (max-width: 900px) {
  .glryMasonry {
    grid-template-columns: 1fr 1fr;
    grid-template-rows: 200px 200px 200px 200px;
  }
  .glryCell { grid-column: auto !important; grid-row: auto !important; }
}
@media (max-width: 580px) {
  .glryMasonry {
    grid-template-columns: 1fr;
    grid-template-rows: repeat(8, 200px);
  }
}

