}

.footerMain {
  display: grid;
  grid-template-columns: 1.3fr 0.8fr 1fr;
  gap: 60px;
  padding: 64px 0 56px;
  align-items: start;
  position: relative;
  z-index: 1;
}

.footerBrand {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

.footerLogo {
  width: 260px;
  height: auto;
  object-fit: contain;
  margin-bottom: 20px;
}

.footerBrandText {
  max-width: 300px;
  color: rgba(255,255,255,.45);
  font-size: 0.9rem;
  line-height: 1.65;
  margin: 0 0 22px;
}

.footerCards {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  align-items: center;
}

.footerCardIcon {
  height: 28px;
  width: auto;
  object-fit: contain;
  display: block;
}

.footerHeading {
  margin: 0 0 20px;
  font-size: 0.74rem;
  font-weight: 700;
  letter-spacing: 0.14em;
  text-transform: uppercase;
  color: rgba(255,255,255,.35);
}

.footerLinks {
  display: flex;
  flex-direction: column;
  gap: 13px;
}

.footerLinks a {
  color: rgba(255,255,255,.65);
  font-size: 0.95rem;
  transition: color .2s;
}

.footerLinks a:hover { color: #ffffff; }

.footerContact {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.footerSocials {
  display: flex;
  gap: 10px;
  align-items: center;
}

.footerSocialBtn {
  width: 38px;
  height: 38px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  color: rgba(255,255,255,.55);
  background: rgba(255,255,255,.05);
  border: 1px solid rgba(255,255,255,.08);
  border-radius: 10px;
  transition: color .2s, background .2s, border-color .2s, transform .2s;
}

.footerSocialBtn:hover {
  color: #ffffff;
  background: rgba(217,31,38,.15);
  border-color: rgba(217,31,38,.3);
  transform: translateY(-2px);
}

.footerContactInfo {
  display: grid;
  gap: 7px;
}

.footerBusiness {
  font-size: 0.95rem;
  font-weight: 700;
  color: #ffffff;
  margin-bottom: 2px;
}

.footerContactInfo p {
  margin: 0;
  color: rgba(255,255,255,.45);
  font-size: 0.88rem;
  line-height: 1.6;
}

.footerBottom {
  background: var(--red);
  position: relative;
  z-index: 1;
}

.footerBottomInner {
  min-height: 52px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 20px;
  position: relative;
}

.footerBottomCopy {
  position: absolute;
  left: 50%;
  transform: translateX(-50%);
  margin: 0;
  color: rgba(255,255,255,.85);
  font-size: 0.82rem;
  white-space: nowrap;
}

.footerBottomLinks {
  display: flex;
  align-items: center;
  gap: 20px;
}

.footerBottomLinks a {
  color: rgba(255,255,255,.75);
  font-size: 0.82rem;
  transition: color .2s;
}

.footerBottomLinks a:hover { color: #ffffff; }

/* =========================
   RESPONSIVE
========================= */

/* ── HAMBURGER ─────────────────────────────────────── */
.navHamburger {
  display: none;
  flex-direction: column;
  justify-content: center;
  gap: 5px;
  width: 40px; height: 40px;
  background: none; border: none; cursor: pointer;
  padding: 6px;
  z-index: 310;
  flex-shrink: 0;
}

.navHamburger span {
  display: block;
  height: 2px; width: 100%;
  background: #ffffff;
  border-radius: 2px;
  transition: transform 0.3s ease, opacity 0.3s ease, width 0.3s ease;
  transform-origin: center;
}

.navHamOpen span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
.navHamOpen span:nth-child(2) { opacity: 0; transform: scaleX(0); }
.navHamOpen span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

/* ── MOBILE DRAWER ──────────────────────────────────── */
.navMobileOverlay {
  position: fixed; inset: 0;
  background: rgba(0,0,0,0.6);
  z-index: 205;
  backdrop-filter: blur(4px);
  animation: fadeIn .2s ease;
}

.navMobileDrawer {
  position: fixed;
  top: 0; right: 0;
  width: 280px; height: 100dvh;
  background: #0a0b0e;
  border-left: 1px solid rgba(255,255,255,.08);
  z-index: 210;
  display: flex;
  flex-direction: column;
  transform: translateX(100%);
  transition: transform 0.35s cubic-bezier(.22,1,.36,1);
  padding-top: 80px;
}

.navMobileOpen { transform: translateX(0); }

.navMobileLinks {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 8px 0;
  overflow-y: auto;
}

.navMobileLink {
  display: block;
  padding: 16px 28px;
  color: rgba(255,255,255,.75);
  font-size: 1.05rem;
  font-weight: 500;
  text-decoration: none;
  border-bottom: 1px solid rgba(255,255,255,.05);
  transition: color .2s, background .2s;
}

.navMobileLink:hover {
  color: #ffffff;
  background: rgba(255,255,255,.04);
}

.navMobileFooter {
  padding: 20px 20px 32px;
  border-top: 1px solid rgba(255,255,255,.07);
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.navMobileBook {
  width: 100%;
  text-align: center;
  border-radius: 12px !important;
}

/* ── TABLET 1120px ──────────────────────────────────── */
@media (max-width: 1120px) {
  .topBarInner { grid-template-columns: 1fr 1fr; }
  .topBarInner > *:last-child { display: none; }

  .navInner {
    grid-template-columns: 1fr auto 1fr;
    height: 68px;
  }
  .navScrolled .navInner { height: 100px; }

  .navMenu { gap: 20px; }
  .navBookBtn { padding: 0 16px; font-size: .78rem; height: 40px; }

  .trustGrid, .trainingGrid, .trainingBody, .trainingHeader,
  .ctLayout, .vehiclesContent { grid-template-columns: 1fr 1fr; }
  .servicesGrid { grid-template-columns: repeat(2,1fr); }
  .splitSection { grid-template-columns: 1fr; }
  .galleryGrid  { grid-template-columns: 1fr 1fr; }
  .footerMain   { grid-template-columns: 1fr 1fr; gap: 40px; }
}

/* ── TABLET narrow 900px — hamburger kicks in ─────── */
@media (max-width: 900px) {
  /* Switch to hamburger */
  .navMenu    { display: none; }
  .navActions { display: none; }
  .navHamburger {
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
    gap: 5px;
    width: 40px; height: 40px;
    background: rgba(255,255,255,.06);
    border: 1px solid rgba(255,255,255,.12);
    border-radius: 10px;
    cursor: pointer;
    flex-shrink: 0;
  }
  .navHamburger span {
    display: block;
    width: 20px; height: 2px;
    background: #ffffff;
    border-radius: 2px;
    transition: transform 0.25s ease, opacity 0.25s ease;
    transform-origin: center;
  }
  .navHamOpen span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
  .navHamOpen span:nth-child(2) { opacity: 0; transform: scaleX(0); }
  .navHamOpen span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

  .navInner {
    display: flex;
    align-items: center;
    justify-content: space-between;
    height: 64px;
    padding: 0;
  }
  .navScrolled .navInner { height: 64px; }

  /* topbar — solo teléfono */
  .topBarInner { grid-template-columns: 1fr; }
  .topBarInner > *:not(:first-child) { display: none; }
  .topBar { height: 36px; }
  .topBarInner { height: 36px; }
  .topItem { justify-content: center; border: none; font-size: .82rem; }

  /* Logo */
  .brandLogo { width: 150px !important; margin-top: 0 !important; }
  .brandScrolled { width: 130px !important; }

  /* Hero — topbar(36) + nav(64) = 100px */
  .hero { min-height: 100dvh; }
  .heroContent { padding-top: 120px; min-height: 100dvh; }
  .innerPage { padding-top: 120px; }

  /* MOBILE MENU OVERLAY */
  .mobileOverlay,
  .mobileMenu { display: flex; }

  .mobileOverlay {
    position: fixed; inset: 0;
    background: rgba(0,0,0,.65);
    z-index: 9997;
    backdrop-filter: blur(4px);
    animation: fadeIn .2s ease;
  }

  /* MOBILE DRAWER */
  .mobileMenu {
    position: fixed;
    top: 0 !important;
    right: 0;
    bottom: 0;
    width: min(320px, 85vw);
    height: 100dvh;
    background: #0b0c10;
    border-left: 1px solid rgba(255,255,255,.08);
    z-index: 9998;
    display: flex;
    flex-direction: column;
    transform: translateX(100%);
    transition: transform .3s cubic-bezier(.22,1,.36,1);
    overflow-y: auto;
  }
  .mobileMenuOpen { transform: translateX(0) !important; }

  .mobileMenuHead {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 20px 20px 16px;
    border-bottom: 1px solid rgba(255,255,255,.07);
  }

  .mobileMenuClose {
    width: 36px; height: 36px;
    background: rgba(255,255,255,.07);
    border: 1px solid rgba(255,255,255,.10);
    border-radius: 8px;
    display: flex; align-items: center; justify-content: center;
    cursor: pointer;
    color: #fff;
    transition: background .15s;
  }
  .mobileMenuClose:hover { background: rgba(255,255,255,.14); }

  .mobileNav {
    flex: 1;
    display: flex;
    flex-direction: column;
    padding: 12px 12px;
    gap: 2px;
    overflow-y: auto;
  }

  .mobileNavLink {
    display: block;
    padding: 14px 16px;
    color: rgba(255,255,255,.8);
    font-size: 1rem;
    font-weight: 600;
    border-radius: 10px;
    transition: background .15s, color .15s;
  }
  .mobileNavLink:hover { background: rgba(255,255,255,.06); color: #fff; }

  .mobileMenuFooter {
    padding: 16px 16px 28px;
    border-top: 1px solid rgba(255,255,255,.07);
    display: flex;
    flex-direction: column;
    gap: 14px;
  }

  .mobileBookBtn {
    width: 100%;
    justify-content: center;
    border-radius: 14px !important;
  }

  .mobileLang {
    display: flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
  }

  /* Sections stack */
  .trustGrid, .servicesGrid, .trainingGrid, .trainingBody,
  .ctLayout, .ctFormRow, .galleryGrid, .footerMain,
  .vehiclesContent { grid-template-columns: 1fr; }

  .trainingHeader { flex-direction: column; align-items: flex-start; }
  .trainingStats  { flex-direction: row; gap: 24px; }
  .trainingStat   { align-items: flex-start; }
  .trainingPreview { position: static; }

  .hero h1,
  .sectionHead h2,
  .splitCopy h2,
  .trnHeroTitle,
  .partsTitle {
    font-size: clamp(2.2rem, 8vw, 3.5rem);
  }

  .heroPrimary { width: 100%; min-width: unset; }
  .heroSecondary { flex: 1; min-width: 120px; }
  .navDropMenu { left: 0; transform: none; }
  .heroButtons { flex-wrap: wrap; }

  /* Footer */
  .footerMain { grid-template-columns: 1fr; gap: 32px; }
  .footerBottomInner { flex-direction: column; text-align: center; gap: 8px; }
  .footerBottomCopy { position: static !important; transform: none !important; }

  /* Parts/Training */
  .partsGrid, .partsLoading { grid-template-columns: 1fr; }
  .trnGrid { grid-template-columns: 1fr; }
  .partsFilters { flex-direction: column; }
  .checkoutMainGrid { grid-template-columns: 1fr; }
  .instrGrid { grid-template-columns: 1fr; }
  .trnEnrollGrid { grid-template-columns: 1fr; }
}

/* ── SMALL MOBILE 420px ─────────────────────────────── */
@media (max-width: 420px) {
  .trnCard, .partCard { border-radius: 14px; }
  .glryMasonry { grid-template-columns: 1fr; grid-template-rows: repeat(8,200px); }
  .glryCell { grid-column: auto !important; grid-row: auto !important; }
  .footerLogo { width: 160px; }
}

/* =========================
   PARTS PAGE
========================= */

/* Page background — matches site dark theme */
.innerPage {
  min-height: 70vh;
  padding: 180px 0 80px;
  background: #07080b;
}

/* HEADER */
.partsHeader {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 24px;
  margin-bottom: 48px;
  flex-wrap: wrap;
  padding-bottom: 40px;
  border-bottom: 1px solid rgba(255,255,255,.07);
}

.partsTitle {
  font-size: clamp(2.8rem, 5vw, 5rem);
  font-weight: 700;
  letter-spacing: -0.05em;
  line-height: 0.92;
  color: #ffffff;
  margin: 10px 0 16px;
}

.partsSub {
  color: rgba(255,255,255,.45);
  font-size: 1.05rem;
  margin: 0;
  max-width: 480px;
}

/* CART BUTTON */
.cartBtn {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  height: 50px;
  padding: 0 22px;
  background: rgba(255,255,255,.04);
  border: 1px solid rgba(255,255,255,.10);
  border-radius: 14px;
  color: #ffffff;
  font-size: 0.92rem;
  font-weight: 600;
  cursor: pointer;
  transition: background .2s, border-color .2s;
  position: relative;
  flex-shrink: 0;
  backdrop-filter: blur(8px);
}
.cartBtn:hover {
  background: rgba(255,255,255,.08);
  border-color: rgba(217,31,38,.35);
}

.cartBadge {
  position: absolute;
  top: -7px; right: -7px;
  width: 22px; height: 22px;
  background: var(--red);
  border-radius: 50%;
  font-size: 0.68rem;
  font-weight: 800;
  display: flex; align-items: center; justify-content: center;
  box-shadow: 0 0 0 3px #07080b;
}

/* FILTERS */
.partsFilters {
  display: flex;
  gap: 12px;
  flex-wrap: wrap;
  margin-bottom: 36px;
  align-items: center;
  background: rgba(255,255,255,.02);
  border: 1px solid rgba(255,255,255,.06);
  border-radius: 16px;
  padding: 16px 20px;
}

.partsSearch {
  flex: 1;
  min-width: 200px;
  background: rgba(255,255,255,.06) !important;
  border-color: rgba(255,255,255,.10) !important;
}

.partsCatSelect {
  min-width: 180px;
  background: rgba(255,255,255,.06) !important;
  border-color: rgba(255,255,255,.10) !important;
  cursor: pointer;
}

.partsCatSelect option { background: #111; }

.partsInStock {
  display: flex;
  align-items: center;
  gap: 8px;
  color: rgba(255,255,255,.55);
  font-size: 0.88rem;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  padding: 8px 0;
}
.partsInStock input { accent-color: var(--red); width: 16px; height: 16px; cursor: pointer; }

/* GRID */
.partsGrid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

/* SKELETON */
.partsLoading {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 16px;
}

.partSkeleton {
  height: 340px;
  border-radius: 18px;
  background: rgba(255,255,255,.03);
  border: 1px solid rgba(255,255,255,.06);
  animation: shimmer 1.6s ease-in-out infinite;
  position: relative;
  overflow: hidden;
}

.partSkeleton::after {
  content: "";
  position: absolute;
  inset: 0;
  background: linear-gradient(90deg, transparent 0%, rgba(255,255,255,.04) 50%, transparent 100%);
  animation: shimmerSlide 1.6s ease-in-out infinite;
}

@keyframes shimmerSlide {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.partsEmpty {
  text-align: center;
  color: rgba(255,255,255,.3);
  padding: 80px 0;
  font-size: 1.1rem;
}

/* PART CARD — glassmorphism */
.partCard {
  background: rgba(255,255,255,.03);
  border: 1px solid rgba(255,255,255,.07);
  border-radius: 20px;
  overflow: hidden;
  transition: border-color .3s ease, transform .3s ease, background .3s ease;
  cursor: default;
}

.partCard:hover {
  border-color: rgba(217,31,38,.3);
  transform: translateY(-4px);
  background: rgba(255,255,255,.05);
}

.partImg {
  height: 200px;
  background: #0d0e12;
  overflow: hidden;
  position: relative;
  border-bottom: 1px solid rgba(255,255,255,.05);
}

.partImg img {
  width: 100%; height: 100%;
  object-fit: cover;
  transition: transform .4s ease;
}

.partCard:hover .partImg img { transform: scale(1.05); }

.partImgPlaceholder {
  width: 100%; height: 100%;
  display: flex; align-items: center; justify-content: center;
  color: rgba(255,255,255,.08);
}

.partOutStock {
  position: absolute; top: 10px; left: 10px;
  background: rgba(0,0,0,.75);
  backdrop-filter: blur(6px);
  color: rgba(255,255,255,.5);
  font-size: .7rem; font-weight: 700;
  padding: 4px 10px; border-radius: 999px;
  letter-spacing: .04em;
}

.partLowStock {
  position: absolute; top: 10px; left: 10px;
  background: rgba(217,31,38,.85);
  backdrop-filter: blur(6px);
  color: #fff;
  font-size: .7rem; font-weight: 700;
  padding: 4px 10px; border-radius: 999px;
  letter-spacing: .04em;
}

.partInfo { padding: 20px; }

.partBrand {
  font-size: .7rem; font-weight: 700;
  color: var(--red); letter-spacing: .1em;
  text-transform: uppercase; margin: 0 0 6px;
}

.partName {
  font-size: 1rem; font-weight: 700;
  color: rgba(255,255,255,.9);
  margin: 0 0 8px; line-height: 1.35;
}

.partDesc {
  font-size: .84rem; color: rgba(255,255,255,.35);
  margin: 0 0 6px; line-height: 1.6;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.partCompat {
  font-size: .76rem; color: rgba(255,255,255,.22);
  margin: 0 0 14px;
}

.partFooter {
  display: flex; align-items: center;
  justify-content: space-between; gap: 10px;
  margin-top: 16px;
  padding-top: 14px;
  border-top: 1px solid rgba(255,255,255,.06);
}

.partPrice {
  font-size: 1.35rem; font-weight: 800;
  color: #ffffff; letter-spacing: -0.02em;
}

.partAddBtn {
  height: 38px; padding: 0 18px;
  background: var(--red); color: #fff;
  border: none; border-radius: 20px 0 20px 0;
  font-size: .78rem; font-weight: 800;
  letter-spacing: .07em; text-transform: uppercase;
  cursor: pointer;
  transition: background .2s, transform .2s, box-shadow .2s;
  white-space: nowrap;
  box-shadow: 0 4px 14px rgba(217,31,38,.25);
}
.partAddBtn:hover:not(:disabled) {
  background: var(--red-dark);
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(217,31,38,.4);
}
.partAddBtn:disabled { background: rgba(255,255,255,.08); color: rgba(255,255,255,.25); cursor: not-allowed; box-shadow: none; }
.partAddBtn.partAdded { background: #16a34a; box-shadow: 0 4px 14px rgba(22,163,74,.3); }

/* CART DRAWER */
.cartBackdrop {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.7);
  z-index: 400;
  backdrop-filter: blur(6px);
  animation: fadeIn .2s ease;
}

@keyframes fadeIn { from { opacity:0 } to { opacity:1 } }

.cartDrawer {
  position: fixed; top: 0; right: 0; bottom: 0;
  width: 400px; max-width: 95vw;
  background: #0c0d11;
  border-left: 1px solid rgba(255,255,255,.08);
  z-index: 401;
  display: flex; flex-direction: column;
  transform: translateX(100%);
  transition: transform .35s cubic-bezier(.22,1,.36,1);
}
.cartDrawer.cartOpen { transform: translateX(0); }

.cartHead {
  display: flex; align-items: center; justify-content: space-between;
  padding: 22px 24px;
  border-bottom: 1px solid rgba(255,255,255,.07);
}
.cartHead h2 { margin: 0; font-size: 1.1rem; font-weight: 700; }

.cartClose {
  width: 34px; height: 34px;
  background: rgba(255,255,255,.06);
  border: 1px solid rgba(255,255,255,.10);
  border-radius: 8px;
  color: #fff; cursor: pointer; font-size: .9rem;
  display: flex; align-items: center; justify-content: center;
  transition: background .2s;
}
.cartClose:hover { background: rgba(255,255,255,.12); }

.cartEmpty {
  color: rgba(255,255,255,.3);
  text-align: center;
  padding: 60px 24px;
  font-size: .95rem;
}

.cartItems {
  flex: 1; overflow-y: auto; padding: 16px 20px;
  display: flex; flex-direction: column; gap: 10px;
}

.cartItem {
  display: flex; align-items: center; gap: 12px;
  background: rgba(255,255,255,.03);
  border: 1px solid rgba(255,255,255,.06);
  border-radius: 14px; padding: 12px 14px;
}

.cartItemImg {
  width: 50px; height: 50px;
  object-fit: cover; border-radius: 8px; flex-shrink: 0;
  background: #111;
}

.cartItemInfo { flex: 1; min-width: 0; }
.cartItemName { margin: 0 0 4px; font-size: .86rem; font-weight: 600; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.cartItemPrice { margin: 0; font-size: .84rem; color: var(--red); font-weight: 700; }

.cartItemQty {
  display: flex; align-items: center; gap: 8px;
}
.cartItemQty button {
  width: 28px; height: 28px; border-radius: 8px;
  background: rgba(255,255,255,.08);
  border: 1px solid rgba(255,255,255,.10);
  color: #fff; font-size: 1.1rem;
  cursor: pointer; display: flex; align-items: center; justify-content: center;
  transition: background .15s;
}
.cartItemQty button:hover { background: rgba(255,255,255,.14); }
.cartItemQty span { font-size: .9rem; font-weight: 700; min-width: 20px; text-align: center; }

.cartItemRemove {
  background: none; border: none;
  color: rgba(255,255,255,.2); cursor: pointer; font-size: .85rem;
  width: 28px; height: 28px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 6px; transition: color .2s, background .2s;
}
