.adminDetailCard table { width:100%; font-size:.88rem; }
.adminDetailCard thead th { text-align:left; color:rgba(255,255,255,.35); font-size:.72rem; padding:6px 0; border-bottom:1px solid rgba(255,255,255,.07); }
.adminDetailCard tbody td { padding:8px 0; border-bottom:1px solid rgba(255,255,255,.05); color:rgba(255,255,255,.7); }

.adminDetailLabel {
  font-size: .72rem;
  font-weight: 700;
  letter-spacing: .08em;
  text-transform: uppercase;
  color: rgba(255,255,255,.3);
  margin: 0 0 4px;
}
